import { OwnerStackError } from '@nordic/utils/error';

export class NordicAssetNotFoundError extends OwnerStackError {
  constructor(assetName: string) {
    super(
      `Asset "${assetName}" not found.` +
        ' Please make sure that you have built all your assets before running your app,' +
        ' or check if you are trying to load a non-existing bundle.',
    );
    this.name = 'NordicAssetNotFoundError';
  }
}
